import React from "react";
import { parseProgrammeHTML } from "./utils/parserProgramme";

function App() {
  const handleImport = async (event) => {
    const file = event.target.files[0];
    if (!file) return;

    const text = await file.text();
    const programme = parseProgrammeHTML(text);

    console.log("PROGRAMME PARSÉ :", programme);
    alert("Regarde la console !");
  };

  return (
    <div style={{ padding: 40, color: "white", background: "black", minHeight: "100vh" }}>
      <h1>FitCoach Import</h1>
      <input type="file" accept=".html" onChange={handleImport} />
    </div>
  );
}

export default App;
